import{_ as e,o as s,c as l,ai as n}from"./chunks/framework.C4ntERNc.js";const b=JSON.parse('{"title":"Global Constant Blocks (@global)","description":"","frontmatter":{"title":"Global Constant Blocks (@global)","lang":"en-US","layout":"doc","outline":"deep"},"headers":[],"relativePath":"reference-manual/formal-reference/global-block.md","filePath":"reference-manual/formal-reference/global-block.md"}'),i={name:"reference-manual/formal-reference/global-block.md"};function t(o,a,r,c,p,d){return s(),l("div",null,[...a[0]||(a[0]=[n(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /jz-hdl/reference-manual/formal-reference/global-block.md for this page in Markdown format</div><h1 id="global-constant-blocks-global" tabindex="-1">Global Constant Blocks (@global) <a class="header-anchor" href="#global-constant-blocks-global" aria-label="Permalink to “Global Constant Blocks (@global)”">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to “Purpose”">​</a></h2><p>Define named collections of sized literal constants visible to all modules and projects within the compilation unit. Useful for instruction encodings, CSR numbers, protocol constants, and other bit-patterns referenced throughout the design.</p><h2 id="syntax" tabindex="-1">Syntax <a class="header-anchor" href="#syntax" aria-label="Permalink to “Syntax”">​</a></h2><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>@global &lt;global_name&gt;</span></span>
<span class="line"><span>  &lt;const_id&gt; = &lt;sized_literal&gt;;</span></span>
<span class="line"><span>  &lt;const_id&gt; = &lt;sized_literal&gt;;</span></span>
<span class="line"><span>  ...</span></span>
<span class="line"><span>@endglob</span></span></code></pre></div><p>Where each sized literal follows the literal syntax: <code>width&#39;base_value</code></p><h2 id="semantics" tabindex="-1">Semantics <a class="header-anchor" href="#semantics" aria-label="Permalink to “Semantics”">​</a></h2><ul><li>The global name creates a namespace root.</li><li>Constants are referenced as <code>global_name.CONST_ID</code>.</li><li>Each constant is a sized literal with explicit, unambiguous bit-width.</li><li>Width must be &gt;= intrinsic width of the value (standard overflow rules apply).</li><li>Multiple <code>@global</code> blocks are allowed; each must have a unique name.</li></ul><h2 id="value-semantics" tabindex="-1">Value semantics <a class="header-anchor" href="#value-semantics" aria-label="Permalink to “Value semantics”">​</a></h2><p>Unlike CONFIG and CONST, global constants <strong>are values</strong> and may be used anywhere a value expression is permitted:</p><ul><li>RHS of assignments (ASYNCHRONOUS or SYNCHRONOUS)</li><li>Operands to operators</li><li>Arguments to intrinsic operators</li><li>Part of expressions, concatenations, conditionals</li></ul><p>Standard width rules apply: same width as target for direct assignment; use <code>=z</code>/<code>=s</code> modifiers for extension.</p><h2 id="errors" tabindex="-1">Errors <a class="header-anchor" href="#errors" aria-label="Permalink to “Errors”">​</a></h2><ul><li>Duplicate global name across the compilation</li><li>Duplicate const_id inside a single block</li><li>Invalid identifier syntax</li><li>Forward reference inside a block</li><li>Non-integer or negative expressions</li><li>Value that is not a properly-sized literal (bare decimal, CONST reference, or CONFIG reference)</li><li>Literal overflow (intrinsic width exceeds declared width)</li><li>Attempting to assign to a global constant (read-only)</li></ul><h2 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to “Example”">​</a></h2><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>@global ISA</span></span>
<span class="line"><span>  INST_ADD   = 17&#39;b0110011_0000000_000;</span></span>
<span class="line"><span>  INST_SUB   = 17&#39;b0110011_0100000_000;</span></span>
<span class="line"><span>  INST_SLL   = 17&#39;b0110011_0000000_001;</span></span>
<span class="line"><span>  INST_AUIPC = 10&#39;b0010111;</span></span>
<span class="line"><span>  INST_LUI   = 10&#39;b0110111;</span></span>
<span class="line"><span>@endglob</span></span></code></pre></div><p>Usage inside a module:</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>ASYNCHRONOUS {</span></span>
<span class="line"><span>  IF (opcode == ISA.INST_ADD) {</span></span>
<span class="line"><span>    alu_op &lt;= 4&#39;b0001;</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span></code></pre></div>`,19)])])}const g=e(i,[["render",t]]);export{b as __pageData,g as default};
